def catalog_brands():
    return sorted({car["brand"] for car in INDIA_CAR_CATALOG})


def catalog_by_brand():
    grouped = {}
    for car in sorted(INDIA_CAR_CATALOG, key=lambda item: (item["brand"], item["model"])):
        grouped.setdefault(car["brand"], []).append(car)
    return grouped


def garage_catalog_payload():
    return {
        brand: [
            {
                "model": car["model"],
                "fuel": car["fuel"],
                "body_style": car["body_style"],
                "price_band": car["price_band"],
            }
            for car in cars
        ]
        for brand, cars in catalog_by_brand().items()
    }


def normalize_catalog_car(car):
    return {
        **car,
        "name": f"{car['brand']} {car['model']}",
        "city_score": _score(car, "city"),
        "highway_score": _score(car, "highway"),
        "family_score": _score(car, "family"),
        "solo_score": _score(car, "solo"),
        "running_cost_score": _score(car, "running"),
        "comfort_score": _score(car, "comfort"),
        "reason": _reason(car),
    }


def recommendation_catalog():
    return [normalize_catalog_car(car) for car in INDIA_CAR_CATALOG]


def _score(car, category):
    tags = set(car.get("tags", []))
    body = car.get("body_style", "").lower()
    fuel = set(car.get("fuel", []))
    if category == "city":
        return 9 if "city" in tags or "hatchback" in body else 7
    if category == "highway":
        return 9 if any(tag in tags for tag in ["highway", "touring", "comfort"]) or "sedan" in body else 7
    if category == "family":
        return 10 if "large-family" in tags else 9 if "family" in tags or any(word in body for word in ["suv", "mpv", "sedan"]) else 7
    if category == "solo":
        return 9 if any(word in body for word in ["hatchback", "coupe", "crossover"]) else 7
    if category == "running":
        return 10 if fuel.intersection({"cng", "electric", "hybrid"}) or "low_running_cost" in tags else 7
    if category == "comfort":
        return 10 if "luxury" in tags else 9 if "comfort" in tags or car.get("price_band") in {"Premium", "Luxury"} else 7
    return 7


def _reason(car):
    tags = set(car.get("tags", []))
    if "electric" in tags:
        return "Electric option for users who want lower running cost and city-friendly ownership."
    if "large-family" in tags:
        return "Practical for bigger families, more passengers and road-trip comfort."
    if "low_running_cost" in tags or "cng" in car.get("fuel", []):
        return "Good fit for daily running with a strong focus on lower ownership cost."
    if "luxury" in tags:
        return "Premium option for comfort, features and a more refined ownership experience."
    if "off-road" in tags or "rough_roads" in tags:
        return "Better suited for rough roads, higher ground clearance and adventure usage."
    return "Balanced choice for everyday Indian car ownership needs."
